export function calculateDiscount(price: number, tiers: {threshold: number, rate: number}[]): number {
  // Guard against invalid input
  if (price == null || isNaN(price)) {
    throw new Error('price must be a valid number');
  }
  // Ensure price is non‑negative
  const safePrice = Math.max(0, price);
  // Find applicable tier using >= to include boundary
  const tier = tiers.find(t => safePrice >= t.threshold);
  if (!tier) return 0;
  // Apply rate, avoid floating point accumulation errors
  const discount = safePrice * tier.rate;
  // Round to 2 decimal places to avoid floating point noise
  return Math.round(discount * 100) / 100;
}
