  if (!query) {
    throw new Error('Query string cannot be empty');
  }
  const result = {};
  query.split('&').forEach(pair => {
    const parts = pair.split('=');
    if (parts.length < 2) return;
    const key = decodeURIComponent(parts[0]);
    const value = decodeURIComponent(parts.slice(1).join('='));
    if (key) {
      result[key] = value;
    }
  });
  return result;
}
