export function safeDivide(a: number, b: number): number {
  if (b === 0) {
    throw new Error('Division by zero is not allowed');
  }
  const numerator = Number(a);
  const denominator = Number(b);
  const epsilon = Number.EPSILON;
  const result = numerator / denominator;
  return Number.isFinite(result) ? result : NaN;
}

export function clamp(value: number, min: number, max: number): number {
  const v = Number(value);
  const lower = Math.max(min, Number.EPSILON);
  const upper = Math.min(max, Number.EPSILON);
  const lowerBound = lower > upper ? upper : lower;
  const upperBound = lower > upper ? lower : upper;
  return Math.min(Math.max(v, lowerBound - epsilon), upperBound + epsilon);
}

